--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -2085,6 +2085,71 @@
 export { getCS, updateMovement };
+
+// ─── Bubble Rendering System ───────────────────────────────────────
+
+/**
+ * Draw a speech bubble above a character at (x, y).
+ * @param ctx CanvasRenderingContext2D
+ * @param x Center x coordinate of bubble tail
+ * @param y Top y coordinate of bubble tail (bubble bottom)
+ * @param text Text to display inside bubble
+ */
+export function drawSpeechBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 4;
+  const textWidth = ctx.measureText(text).width;
+  const bubbleWidth = textWidth + paddingX * 2;
+  const bubbleHeight = 18;
+  const bubbleX = x - bubbleWidth / 2;
+  const bubbleY = y - bubbleHeight - 8;
+
+  // Bubble background
+  ctx.fillStyle = '#f0ead6';
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bubbleX, bubbleY, bubbleWidth, bubbleHeight, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail of speech bubble (pointing down)
+  ctx.beginPath();
+  ctx.moveTo(x - 4, bubbleY + bubbleHeight);
+  ctx.lineTo(x, bubbleY + bubbleHeight + 6);
+  ctx.lineTo(x + 4, bubbleY + bubbleHeight);
+  ctx.fillStyle = '#f0ead6';
+  ctx.fill();
+  ctx.stroke();
+
+  // Text inside bubble
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bubbleX + paddingX, bubbleY + 13);
+}
+
+/**
+ * Draw a thought bubble above a character at (x, y).
+ * @param ctx CanvasRenderingContext2D
+ * @param x Center x coordinate of bubble tail
+ * @param y Top y coordinate of bubble tail (bubble bottom)
+ * @param text Text to display inside bubble
+ */
+export function drawThoughtBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  ctx.font = '9px monospace';
+  const paddingX = 6;
+  const paddingY = 4;
+  const textWidth = ctx.measureText(text).width;
+  const bubbleWidth = textWidth + paddingX * 2;
+  const bubbleHeight = 18;
+  const bubbleX = x - bubbleWidth / 2;
+  const bubbleY = y - bubbleHeight - 8;
+
+  // Bubble background (lighter blue)
+  ctx.fillStyle = '#d8e8f8';
+  ctx.strokeStyle = '#2a2020';
+  ctx.lineWidth = 1.5;
+  roundRect(ctx, bubbleX, bubbleY, bubbleWidth, bubbleHeight, 4);
+  ctx.fill();
+  ctx.stroke();
+
+  // Tail of thought bubble (small circles)
+  ctx.fillStyle = '#d8e8f8';
+  ctx.stroke();
+  ctx.beginPath();
+  ctx.arc(x - 2, bubbleY + bubbleHeight + 10, 2, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+  ctx.beginPath();
+  ctx.arc(x - 6, bubbleY + bubbleHeight + 14, 1.5, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.stroke();
+
+  // Text inside bubble
+  ctx.fillStyle = '#1a1020';
+  ctx.fillText(text, bubbleX + paddingX, bubbleY + 13);
+}
+
